#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $cgi = CGI->new;

# Get the redirect URL from the 'next' parameter
my $next = $cgi->param('next') || '';

# Define allowed redirect paths (allowlist)
my @allowed_paths = (
    '/dashboard',
    '/profile',
    '/home',
    '/settings',
    '/welcome',
);

# Default safe redirect
my $default_redirect = '/dashboard';
my $redirect_url = $default_redirect;

# Validate and sanitize the redirect URL
if ($next) {
    # Remove any leading/trailing whitespace
    $next =~ s/^\s+|\s+$//g;
    
    # Check if it's a relative path starting with /
    if ($next =~ m{^/[a-zA-Z0-9/_-]+$}) {
        # Extract the base path (first segment after /)
        my ($base_path) = $next =~ m{^(/[^/\?#]+)};
        
        # Check if the base path is in our allowlist
        if (grep { $_ eq $base_path } @allowed_paths) {
            $redirect_url = $next;
        }
    }
}

# Send the redirect header
print $cgi->header(
    -type => 'text/html',
    -status => '302 Found',
    -location => $redirect_url
);

print "<html><body>Redirecting...</body></html>\n";